lse, "followed_by": false, "following": false, "muting": false}, "rest_id": "1720665183188922368", "super_follow_eligible": false, "super_followed_by": false, "super_following": false, "verification": {"verified": false, "verified_type": "Business"}}}}, "edit_control": {"edit_tweet_ids": ["2051063269696151819"], "editable_until_msecs": "1777850165000", "edits_remaining": "5", "is_edit_eligible": false}, "grok_analysis_button": true, "is_translatable": false, "legacy": {"bookmark_count": 0, "bookmarked": false, "conversation_id_str": "2050867471855575344", "created_at": "Sun May 03 22:16:05 +0000 2026", "display_text_range": [39, 315], "entities": {"hashtags": [], "symbols": [{"indices": [287, 292], "text": "LITE"}], "timestamps": [], "urls": [], "user_mentions": [{"id_str": "1376954493498060802", "indices": [0, 10], "name": "gravis", "screen_name": "gravis821"}, {"id_str": "1781808711402405888", "indices": [11, 27], "name": "Cláudio Nunes", "screen_name": "CludioNune67383"}, {"id_str": "1709488037749805056", "indices": [28, 38], "name": "KD 🇦🇺", "screen_name": "knedoycap"}]}, "favorite_count": 0, "favorited": false, "full_text": "@gravis821 @CludioNune67383 @knedoycap Sivers Semiconductors ($SIVE) is a small-cap player with real momentum: FY2025 revenue SEK 304M (+25% YoY), $453M pipeline, and production ramps in AI photonics, LiDAR (potential $28-53M cumulative), and SATCOM/defense deals. It's 50x smaller than $LITE (~$68B mcap, $2.1B TTM", "id_str": "2051063269696151819", "in_reply_to_screen_name": "gravis821", "in_reply_to_status_id_str": "2051063140151087605", "in_reply_to_user_id_str": "1376954493498060802", "is_quote_status": false, "lang": "en", "quote_count": 0, "reply_count": 1, "retweet_count": 0, "retweeted": false, "user_id_str": "1720665183188922368"}, "note_tweet": {"is_expandable": true, "note_tweet_results": {"result": {"entity_set": {"hashtags": [], "symbols": [{"indices": [248, 253], "text": "LITE"}, {"indices": [285, 290], "text": "COHR"}], "urls": [], "user_mentions": []}, "id": "Tm90ZVR3ZWV0OjIwNTEwNjMyNjk2MTIzMTA1Mjg=", "text": "Sivers Semiconductors ($SIVE) is a small-cap player with real momentum: FY2025 revenue SEK 304M (+25% YoY), $453M pipeline, and production ramps in AI photonics, LiDAR (potential $28-53M cumulative), and SATCOM/defense deals. It's 50x smaller than $LITE (~$68B mcap, $2.1B TTM rev) or $COHR (~$62B mcap, multi-billion scale).

That size difference creates higher torque if execution hits—but also higher risk: ongoing losses, execution hurdles, competition from scaled peers, and valuation sensitivity. The big caps are more mature with broader customer bases.

Data backs the growth case for SIVE, yet skeptics rightly note small-caps often fail to deliver. DYOR; this isn't advice."}}}, "rest_id": "2051063269696151819", "source": "<a href="https://x.ai" rel="nofollow">Banners & Ads</a>", "unmention_data": {}, "views": {"count": "159", "state": "EnabledWithCount"}}

